ItCaseLearning.Example:
```typescript
it("should retry once and return the normalized payload", async () => {
  // purpose: verify retry policy at the contract boundary, not transport internals
  // invariant: success requires exactly one retry before normalization succeeds
  // failure mode: avoid splitting result and retry count into unrelated asserts
});
```

CompactExamples.Example:
```typescript
it("should build a lowercase slug from the title", async () => {
  // START_BUILD_SLUG_SETUP_INPUT
  const input = { title: "Hello World", separator: "-" };
  // END_BUILD_SLUG_SETUP_INPUT

  // START_BUILD_SLUG_TRIGGER_EXECUTION
  const slug = await unwrap(builder.build(input));
  // END_BUILD_SLUG_TRIGGER_EXECUTION

  // START_BUILD_SLUG_ASSERT_RESULT
  assert.strictEqual(slug, "hello-world");
  // END_BUILD_SLUG_ASSERT_RESULT
});
```

```typescript
it("should retry once and return the normalized payload", async () => {
  // purpose: verify retry policy at the contract boundary, not transport internals
  // contract: one transient failure is tolerated before success is returned
  // failure mode: do not wrap the returned result into a synthetic summary object when the contract shape is already explicit

  // START_FETCH_ITEM_SETUP_MOCKS
  const tracker = mockEnv.interceptMultiple("GET", url, [
    () => ({ status: 503, body: "Service Unavailable" }),
    () => ({ status: 200, body: { id: 42, name: "Keyboard", inStock: true } }),
  ]);
  // END_FETCH_ITEM_SETUP_MOCKS

  // START_FETCH_ITEM_TRIGGER_REQUEST
  const result = await client.fetchItem(url);
  // END_FETCH_ITEM_TRIGGER_REQUEST

  // START_FETCH_ITEM_ASSERT_RESULT
  assert.deepStrictEqual(result, {
    ok: true,
    status: 200,
    data: { id: 42, name: "Keyboard", inStock: true },
  });
  assert.strictEqual(tracker.getAttemptCount(), 2);
  // END_FETCH_ITEM_ASSERT_RESULT
});
```
